import React, { useEffect, useState } from "react";
import { useSelector } from "react-redux";
import { useNavigate, useParams } from "react-router-dom";
import { Textarea } from "../components/utils/Input";
import Loader from "../components/utils/Loader";
import useFetch from "../hooks/useFetch";
import MainLayout from "../layouts/MainLayout";
import validateManyFields from "../validations";

const Task = () => {
  const { token } = useSelector((state) => state.authReducer);
  const navigate = useNavigate();
  const [fetchData, { loading }] = useFetch();
  const { taskId } = useParams();

  const mode = taskId ? "update" : "add";

  const [task, setTask] = useState(null);
  const [formData, setFormData] = useState({
    description: "",
  });
  const [formErrors, setFormErrors] = useState({});

  // 🧠 Page title
  useEffect(() => {
    document.title = mode === "add" ? "Add Task" : "Update Task";
  }, [mode]);

  // 🔄 Fetch existing task
  useEffect(() => {
    if (mode === "update" && token) {
      const config = {
        url: `/tasks/${taskId}`,
        method: "get",
        headers: { Authorization: `Bearer ${token}` },
      };

      fetchData(config, { showSuccessToast: false })
        .then((data) => {
          if (data?.task) {
            setTask(data.task);
            setFormData({
              description: data.task.description || "",
            });
          }
        })
        .catch((err) => {
          console.error("Fetch Task Error:", err);
        });
    }
  }, [mode, token, taskId, fetchData]);

  // ✏️ Handle input
  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  // 🔄 Reset form
  const handleReset = (e) => {
    e.preventDefault();
    setFormData({
      description: task?.description || "",
    });
  };

  // ✅ Submit form
  const handleSubmit = async (e) => {
    e.preventDefault();

    console.log("FORM DATA:", formData); // 🔥 DEBUG

    const errors = validateManyFields("task", formData);
    setFormErrors({});

    if (errors.length > 0) {
      const formattedErrors = errors.reduce(
        (acc, cur) => ({ ...acc, [cur.field]: cur.err }),
        {}
      );
      setFormErrors(formattedErrors);
      return;
    }

    try {
      const config = {
        url: mode === "add" ? "/tasks" : `/tasks/${taskId}`,
        method: mode === "add" ? "post" : "put",
        data: formData, // 🔥 IMPORTANT
        headers: { Authorization: `Bearer ${token}` },
      };

      const res = await fetchData(config);

      console.log("API RESPONSE:", res);

      navigate("/");
    } catch (err) {
      console.error("Submit Error:", err.response?.data || err.message);
    }
  };

  // ⚠️ Error UI
  const fieldError = (field) => (
    <p
      className={`mt-1 text-pink-600 text-sm ${
        formErrors[field] ? "block" : "hidden"
      }`}
    >
      <i className="mr-2 fa-solid fa-circle-exclamation"></i>
      {formErrors[field]}
    </p>
  );

  return (
    <MainLayout>
      <form className="m-auto my-16 max-w-[1000px] bg-white p-8 border-2 shadow-md rounded-md">
        {loading ? (
          <Loader />
        ) : (
          <>
            <h2 className="text-center mb-4">
              {mode === "add" ? "Add New Task" : "Edit Task"}
            </h2>

            <div className="mb-4">
              <label htmlFor="description">Description</label>
              <Textarea
                name="description"
                id="description"
                value={formData.description}
                placeholder="Write here..."
                onChange={handleChange}
              />
              {fieldError("description")}
            </div>

            {/* ✅ Submit */}
            <button
              type="submit"
              className="bg-primary text-white px-4 py-2 font-medium hover:bg-primary-dark"
              onClick={handleSubmit}
            >
              {mode === "add" ? "Add Task" : "Update Task"}
            </button>

            {/* ❌ Cancel */}
            <button
              type="button"
              className="ml-4 bg-red-500 text-white px-4 py-2 font-medium"
              onClick={() => navigate("/")}
            >
              Cancel
            </button>

            {/* 🔄 Reset */}
            {mode === "update" && (
              <button
                type="button"
                className="ml-4 bg-blue-500 text-white px-4 py-2 font-medium hover:bg-blue-600"
                onClick={handleReset}
              >
                Reset
              </button>
            )}
          </>
        )}
      </form>
    </MainLayout>
  );
};

export default Task;
